insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000005', 17, 'B1', 'Verbos con preposición y el genitivo', 'En alemán muchos verbos llevan una preposición fija que no se traduce del español, y cada una exige su caso. Además verás el genitivo (des/der) para decir de quién es algo.', '[{"heading": "El verbo trae su preposición pegada", "body": "En alemán el verbo y su preposición forman una sola pieza. La preposición casi nunca coincide con la española: «esperar a» es warten auf, «pensar en» es denken an. No la traduzcas: apréndela junto al verbo, como si fuera parte de la palabra.", "bullets": ["warten auf = esperar (a)", "denken an = pensar (en)", "sich interessieren für = interesarse (por)", "sich freuen auf = hacer ilusión (algo futuro)"]}, {"heading": "Cada preposición trae su caso fijo", "body": "Aprende el paquete completo: verbo + preposición + caso. Con warten auf, denken an y sich freuen auf el caso es acusativo. Con Angst haben vor y teilnehmen an es dativo. Ese caso lo fija el verbo; no cambia según el movimiento.", "bullets": ["Acusativo: warten auf den Bus, denken an meinen Bruder", "Dativo: Angst haben vor dem Hund; teilnehmen an → am Kurs.", "Memoriza las tres cosas juntas, nunca por separado"]}, {"heading": "El genitivo: de quién es", "body": "El genitivo indica pertenencia. El artículo masculino y neutro pasa a des; el femenino y el plural, a der. Además, masculino y neutro añaden -s al sustantivo: des Vaters, des Kindes. El femenino no añade nada: der Blume (los masculinos débiles hacen -n: des Studenten).", "bullets": ["das Auto des Vaters: masculino, des y sustantivo con -s", "die Farbe der Blume: femenino, der y sin -s", "El genitivo va detrás del sustantivo poseído"]}]'::jsonb, '[{"de": "Ich warte auf den Bus.", "es": "Espero el autobús.", "text": "Ich warte auf den Bus.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/016382ae-c1d5-5688-ab14-d2cbbc66d746.mp3"}, {"de": "Ich habe Angst vor dem Hund.", "es": "Tengo miedo al perro.", "text": "Ich habe Angst vor dem Hund.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e5f707f6-578c-5c1f-8bc2-219001a3077b.mp3"}, {"de": "Wir nehmen am Kurs teil.", "es": "Participamos en el curso.", "text": "Wir nehmen am Kurs teil.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e198c2ef-09d0-58e2-a873-817ea02a24fe.mp3"}, {"de": "Das Auto des Vaters ist neu.", "es": "El coche del padre es nuevo.", "text": "Das Auto des Vaters ist neu.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/a1f00a0b-3e34-531b-ba70-9ca669c7178b.mp3"}]'::jsonb, '[{"title": "No traduzcas la preposición desde el español", "body": "«Esperar a» no es warten zu ni warten für: es warten auf. «Pensar en» no es denken in: es denken an. La preposición alemana no se deduce de la española, así que se aprende junto al verbo."}, {"title": "«an» no siempre lleva el mismo caso", "body": "Con denken an va acusativo (Ich denke an meinen Bruder), pero con teilnehmen an va dativo (Ich nehme an dem Kurs teil). El caso lo decide el verbo, no la preposición: por eso se memoriza el paquete entero."}, {"title": "La -s del genitivo solo es de masculino y neutro", "body": "des Vaters, des Kindes llevan -s; der Blume no lleva nada. Y ojo: al hablar, los alemanes suelen usar von + dativo (das Auto von meinem Vater). Se entiende perfectamente; el genitivo es la forma escrita y cuidada."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige el genitivo correcto: «Das Auto ___ ist neu.» (el coche del padre; der Vater es masculino)", "options": ["des Vaters", "des Vater", "der Vaters"], "answer": "des Vaters", "id": "u17q1"}, {"type": "multiple_choice", "prompt": "Elige el genitivo correcto: «Die Farbe ___ ist rot.» (el color de la flor; die Blume es femenino)", "options": ["der Blume", "der Blumes", "des Blume"], "answer": "der Blume", "id": "u17q2"}, {"type": "multiple_choice", "prompt": "«warten auf» pide acusativo: «Ich warte auf ___ Bus.»", "options": ["den", "dem", "des"], "answer": "den", "id": "u17q3"}, {"type": "cloze", "prompt": "Escribe la preposición que exige el verbo denken (pensar en alguien).", "text": "Ich denke oft ___ meinen Bruder.", "answer": "an", "accepted": ["an"], "id": "u17q4"}, {"type": "cloze", "prompt": "Escribe la preposición que exige la expresión Angst haben (tener miedo de algo).", "text": "Ich habe Angst ___ dem Hund.", "answer": "vor", "accepted": ["vor"], "id": "u17q5"}]'::jsonb)
