insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000005', 18, 'B1', 'Lo que habría pasado (condicional irreal)', 'Para hablar de lo que habría pasado (pero no pasó), el alemán usa hätte o wäre más el participio al final. Aquí aprendes a formarlo y a ordenar la frase con wenn.', '[{"heading": "hätte / wäre + participio", "body": "El condicional del pasado se forma con hätte o wäre más el Partizip II, que va al final de la frase: «Ich hätte dir geholfen» (te habría ayudado). Habla de algo que NO ocurrió.", "bullets": ["hätte / wäre va en la posición del verbo (segunda).", "El participio cierra la frase: geholfen, gekommen, gewusst.", "Expresa lo irreal: no ocurrió, solo lo imaginamos."]}, {"heading": "¿hätte o wäre? El mismo auxiliar del Perfekt", "body": "Si el verbo forma el Perfekt con haben, usas hätte; si lo forma con sein (movimiento o cambio de estado), usas wäre. No hay que aprender una lista nueva: es la misma elección de siempre.", "bullets": ["ich habe gelernt → ich hätte gelernt.", "ich bin gekommen → ich wäre gekommen.", "Movimiento o cambio —y sein, bleiben, werden— llevan wäre."]}, {"heading": "La frase con wenn: el auxiliar al final", "body": "En la subordinada con wenn, el verbo conjugado se va al final, incluso detrás del participio: «Wenn ich das gewusst hätte, wäre ich gekommen». Fíjate en el orden gewusst hätte, no hätte gewusst.", "bullets": ["wenn + ... + participio + hätte/wäre.", "Si la frase abre con «wenn», hätte/wäre encabeza la principal.", "También sirve para arrepentirse: Ich hätte mehr lernen sollen."]}]'::jsonb, '[{"de": "Ich hätte dir gern geholfen.", "es": "Me habría gustado ayudarte.", "text": "Ich hätte dir gern geholfen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/4cdee9e5-25e8-5349-86a0-54715ff413c4.mp3"}, {"de": "Wir wären gestern früher gekommen.", "es": "Ayer habríamos venido antes.", "text": "Wir wären gestern früher gekommen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/030ff477-b535-5c2b-b151-639f36621efa.mp3"}, {"de": "Wenn ich das gewusst hätte, wäre ich zu Hause geblieben.", "es": "Si lo hubiera sabido, me habría quedado en casa.", "text": "Wenn ich das gewusst hätte, wäre ich zu Hause geblieben.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/4e1d768a-f5fd-5ad3-9f42-40e29d6b5a15.mp3"}, {"de": "Du hättest mehr lernen sollen.", "es": "Deberías haber estudiado más.", "text": "Du hättest mehr lernen sollen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/45de73b9-2a7e-5e0d-805c-afb21fa99bb0.mp3"}]'::jsonb, '[{"title": "«habría venido» no se dice con würde", "body": "El español calca: «würde gekommen sein» suena mal en alemán. Para el pasado irreal se usa directamente wäre gekommen o hätte geholfen. Reserva würde para el presente irreal: «Ich würde kommen»."}, {"title": "Con wenn, el auxiliar va DETRÁS del participio", "body": "Muchos escriben «Wenn ich das hätte gewusst». En la subordinada el verbo conjugado cierra la frase: «Wenn ich das gewusst hätte». El participio va justo antes del auxiliar, no después. Excepción: con dos infinitivos el auxiliar va delante («Wenn ich mehr hätte lernen können…»)."}, {"title": "Elegir el auxiliar equivocado", "body": "«Ich hätte gekommen» es un error frecuente. Como el Perfekt es «ich bin gekommen», el condicional es «ich wäre gekommen». Pregúntate siempre qué auxiliar usa ese verbo en el Perfekt."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Completa: «Ich ___ dir gern geholfen.» (me habría gustado ayudarte)", "options": ["hätte", "hatte", "würde"], "answer": "hätte", "id": "u18q1"}, {"type": "multiple_choice", "prompt": "El verbo kommen forma el Perfekt con sein. ¿Cuál es el condicional del pasado?", "options": ["Ich wäre gekommen.", "Ich hätte gekommen.", "Ich würde gekommen sein."], "answer": "Ich wäre gekommen.", "id": "u18q2"}, {"type": "multiple_choice", "prompt": "¿Cuál tiene el orden correcto en la frase con wenn?", "options": ["Wenn ich das gewusst hätte, wäre ich gekommen.", "Wenn ich das hätte gewusst, wäre ich gekommen.", "Wenn ich hätte das gewusst, wäre ich gekommen."], "answer": "Wenn ich das gewusst hätte, wäre ich gekommen.", "id": "u18q3"}, {"type": "cloze", "prompt": "Escribe el participio de wissen (saber).", "text": "Wenn ich das ___ hätte, wäre ich zu Hause geblieben.", "answer": "gewusst", "accepted": ["gewusst"], "id": "u18q4"}, {"type": "cloze", "prompt": "Escribe el participio de kommen (venir).", "text": "Wir wären gestern früher ___.", "answer": "gekommen", "accepted": ["gekommen"], "id": "u18q5"}]'::jsonb)
