insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000005', 19, 'B2', 'Discurso indirecto formal (Konjunktiv I)', 'El Konjunktiv I es la marca escrita del estilo indirecto: repites lo que otro dijo sin comprometerte con su verdad. Se forma con la raíz del infinitivo + -e, y cuando coincide con el indicativo se pasa al Konjunktiv II.', '[{"heading": "Para qué sirve: citar sin firmar", "body": "En prensa e informes, el alemán marca en el verbo que estás citando: repites lo dicho sin hacerlo tuyo. El español usa indicativo y ese matiz de distancia simplemente se pierde al traducir.", "bullets": ["Marca de cita, no de duda ni de irrealidad.", "Registro escrito: prensa, informes, actas, tribunales.", "En el habla cotidiana casi no se usa."]}, {"heading": "Formación: raíz del infinitivo + -e", "body": "kommen → er komme, haben → er habe, gehen → er gehe. La tercera persona pierde la -t del indicativo y gana -e. El verbo sein va por libre: er sei, sie seien, sin -e en singular.", "bullets": ["er komme, er habe, er gehe: siempre con -e.", "sei es la forma más frecuente y la más irregular.", "Plural de sein: sie seien, distinto de sind."]}, {"heading": "La regla de sustitución: Konjunktiv II", "body": "Si la forma del Konjunktiv I coincide con el indicativo, no marcaría nada: se cambia al Konjunktiv II. Ocurre sobre todo en plural: sie haben es también indicativo, así que se escribe sie hätten.", "bullets": ["sie haben coincide con el indicativo, por eso sie hätten.", "El singular suele distinguirse: er habe, er komme.", "Con sein nunca hace falta sustituir."]}]'::jsonb, '[{"de": "Der Minister sagte, er sei zufrieden.", "es": "El ministro dijo que estaba satisfecho.", "text": "Der Minister sagte, er sei zufrieden.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/fde6fcca-bc8a-55b7-ac43-16452dd08fc0.mp3"}, {"de": "Die Zeitung schreibt, das Unternehmen habe die Zahlen geprüft.", "es": "El periódico escribe que la empresa ha revisado las cifras.", "text": "Die Zeitung schreibt, das Unternehmen habe die Zahlen geprüft.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/b0a3b4c9-6863-5d65-a951-9581a3145236.mp3"}, {"de": "Der Sprecher erklärte, die Verhandlungen seien schwierig.", "es": "El portavoz explicó que las negociaciones eran difíciles.", "text": "Der Sprecher erklärte, die Verhandlungen seien schwierig.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/23e2590f-0e15-5e2c-8a22-4e55e1104875.mp3"}, {"de": "Sie berichteten, die Mitarbeiter hätten keine Informationen.", "es": "Informaron que los empleados no tenían información.", "text": "Sie berichteten, die Mitarbeiter hätten keine Informationen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/861be2da-63b3-516d-a78c-680c1f374599.mp3"}]'::jsonb, '[{"title": "sei no es wäre", "body": "sei repite lo dicho de forma neutral; wäre añade duda o irrealidad y suena a que dudas del que habla. En un titular normal se escribe: Der Minister sagte, er sei zufrieden."}, {"title": "El indicativo no es un error", "body": "En el habla cotidiana se dice sin problema: Er sagte, er ist zufrieden. No está mal, es otro registro. El Konjunktiv I es la opción escrita y formal, no la única correcta."}, {"title": "Sin dass, el verbo va en segunda posición", "body": "Er sagte, der Minister komme später (verbo en segunda posición). Si pones dass, el verbo se va al final: Er sagte, dass der Minister später komme."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Un periódico repite lo que dijo el ministro, sin comprometerse con su verdad. Elige la forma neutral del estilo indirecto formal: Der Minister sagte, er ___ zufrieden.", "options": ["sei", "ist", "wäre"], "answer": "sei", "id": "u19q1"}, {"type": "multiple_choice", "prompt": "En plural, el Konjunktiv I de haben coincide con el indicativo. ¿Qué se escribe entonces en un informe? Die Abgeordneten erklärten, sie ___ keine Zeit.", "options": ["haben", "hätten", "seien"], "answer": "hätten", "id": "u19q2"}, {"type": "multiple_choice", "prompt": "Aquí la forma del Konjunktiv I sí se distingue del indicativo, así que no hay que sustituirla: Der Sprecher sagte, die Zahlen ___ korrekt.", "options": ["seien", "sind", "sein"], "answer": "seien", "id": "u19q3"}, {"type": "multiple_choice", "prompt": "Estilo indirecto formal: «Der Sprecher betonte, das Unternehmen ___ alle Zahlen geprüft.»", "options": ["habe", "hat", "haben"], "answer": "habe", "id": "u19q4"}, {"type": "multiple_choice", "prompt": "Estilo indirecto formal: «Die Zeitung berichtete, der Minister ___ erst am Montag zurück.»", "options": ["komme", "kommt", "kommen"], "answer": "komme", "id": "u19q5"}]'::jsonb)
