insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000005', 20, 'B2', 'Pasiva avanzada (modales, estado, alternativas)', 'Cómo se combina la pasiva con verbos modales, cuándo «sein + Partizip» expresa el estado y qué alternativas (man, sich lassen, sein + zu) prefiere el alemán real.', '[{"heading": "Pasiva con modal: «werden» cierra la frase", "body": "Con un verbo modal, el modal se conjuga en la posición 2 y la pasiva se va entera al final: participio + werden en infinitivo. En pasado se conjuga el modal: «Das musste heute gemacht werden». Ese bloque final nunca se separa ni se invierte.", "bullets": ["Esquema: modal conjugado + … + Partizip + werden (infinitivo).", "«Der Text muss übersetzt werden.» — werden va al final.", "Pasado: musste, konnte, sollte + Partizip + werden."]}, {"heading": "Proceso (werden) frente a estado (sein)", "body": "«werden + Partizip» describe el PROCESO: algo está ocurriendo. «sein + Partizip» describe el ESTADO resultante: algo ya está así. No es una diferencia de estilo; cambiar uno por otro cambia lo que dices.", "bullets": ["Proceso: «Das Fenster wird geöffnet» (alguien lo abre ahora).", "Estado: «Das Fenster ist geöffnet» (ya está abierto).", "Marcas de proceso: gerade, jetzt, un agente con von."]}, {"heading": "Lo que el alemán prefiere: man, sich lassen, sein + zu", "body": "En la lengua real la pasiva larga se evita. «man» + activa es la fórmula más frecuente. «sich lassen» + infinitivo expresa posibilidad («se puede»). «sein + zu» + infinitivo expresa posibilidad u obligación en registro formal o escrito.", "bullets": ["man es sujeto impersonal; el verbo va en tercera persona singular.", "«Das lässt sich machen» = «Das kann gemacht werden».", "«Der Text ist zu korrigieren» = hay que corregirlo (formal)."]}]'::jsonb, '[{"de": "Das muss heute gemacht werden.", "es": "Esto debe hacerse hoy.", "text": "Das muss heute gemacht werden.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/0e4ebd48-5319-57e7-a093-aaad376b37c8.mp3"}, {"de": "Die Tür ist seit gestern geschlossen.", "es": "La puerta está cerrada desde ayer.", "text": "Die Tür ist seit gestern geschlossen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/3946e649-b8c7-5aa6-bce2-ed1523308457.mp3"}, {"de": "Das Problem lässt sich leicht lösen.", "es": "El problema se puede resolver fácilmente.", "text": "Das Problem lässt sich leicht lösen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/d9f56b4b-5064-52ee-8d1c-a82d0691a8b6.mp3"}, {"de": "In Deutschland trennt man den Müll.", "es": "En Alemania se separa la basura.", "text": "In Deutschland trennt man den Müll.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ea6f6001-54d5-515e-892e-3bae46649fef.mp3"}]'::jsonb, '[{"title": "«muss werden gemacht» no existe", "body": "El hispanohablante coloca el auxiliar antes del participio, como en español. En alemán el orden es al revés: primero el participio y después werden, y ambos van al final: «Das muss heute gemacht werden», «Das musste gestern gemacht werden»."}, {"title": "«ist geschlossen» no es «wird geschlossen»", "body": "«Die Bank wird um 18 Uhr geschlossen» = la cierran a las 18 (proceso). «Die Bank ist seit 18 Uhr geschlossen» = ya está cerrada (estado). Con gerade, jetzt o un agente con von, la frase describe siempre el proceso."}, {"title": "man se escribe con una sola n", "body": "«man» es obligatorio como sujeto: «Hier raucht man nicht». No vale «Hier raucht nicht» ni el calco «Hier raucht sich nicht»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "El informe hay que escribirlo hoy. ¿Qué frase tiene el orden correcto de la pasiva con modal?", "options": ["Der Bericht muss heute geschrieben werden.", "Der Bericht muss heute werden geschrieben.", "Der Bericht wird heute schreiben müssen."], "answer": "Der Bericht muss heute geschrieben werden.", "id": "u20q1"}, {"type": "multiple_choice", "prompt": "El taller ya terminó de arreglar el coche. ¿Qué frase describe el RESULTADO, no el proceso?", "options": ["Das Auto ist repariert.", "Das Auto wird repariert.", "Das Auto muss repariert werden."], "answer": "Das Auto ist repariert.", "id": "u20q2"}, {"type": "multiple_choice", "prompt": "«Esto se puede reparar», expresado con la construcción sich lassen. ¿Cuál es correcta?", "options": ["Das lässt sich reparieren.", "Das wird sich reparieren.", "Das lässt sich zu reparieren."], "answer": "Das lässt sich reparieren.", "id": "u20q3"}, {"type": "cloze", "prompt": "Ahora mismo están renovando el museo: la obra está en curso. Completa con la pasiva de proceso.", "text": "Das Museum ___ gerade renoviert.", "answer": "wird", "accepted": ["wird"], "id": "u20q4"}, {"type": "multiple_choice", "prompt": "Alternativa impersonal a la pasiva: «Hier spricht ___ Spanisch.»", "options": ["man", "Mann", "es"], "answer": "man", "id": "u20q5"}]'::jsonb)
