insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000005', 21, 'B2', 'Participios como adjetivos (Partizip I/II)', 'En alemán el participio puede ir DELANTE del sustantivo, declinado como un adjetivo. Equivale a una frase de relativo: Partizip II (pasivo, terminado) y Partizip I (activo, simultáneo).', '[{"heading": "El participio va delante del sustantivo", "body": "El alemán coloca el participio entre el artículo y el sustantivo, como un adjetivo, y lo declina igual. El español no puede hacerlo así: hay que desplegarlo en una frase de relativo. «das reparierte Auto» = «el coche que fue reparado».", "bullets": ["Estructura: artículo + participio declinado + sustantivo.", "Equivale siempre a una frase de relativo en español.", "La terminación sigue las reglas normales del adjetivo."]}, {"heading": "Partizip II: acción terminada, sentido pasivo", "body": "Se forma con ge- + raíz + -t/-en (gekocht, gestohlen). Antepuesto a un verbo transitivo indica que la acción ya se hizo SOBRE el sustantivo: «die gestohlenen Fahrräder» = «las bicicletas que fueron robadas».", "bullets": ["«das gekochte Ei» = el huevo que ha sido cocido.", "El sustantivo RECIBE la acción, no la hace.", "Muchos ya funcionan como adjetivos normales: geöffnet, geschlossen.", "Verbos en -ieren sin ge- (repariert); con prefijo, dentro: eingeladen."]}, {"heading": "Partizip I: acción simultánea, sentido activo", "body": "Se forma con el infinitivo + -d (spielen → spielend) y también se declina. Aquí el sustantivo HACE la acción, al mismo tiempo: «die spielenden Kinder» = «los niños que juegan / están jugando».", "bullets": ["Formación: infinitivo completo + -d, luego la terminación.", "«das kochende Wasser» = el agua que está hirviendo.", "Solo existe como adjetivo o adverbio, nunca como tiempo verbal."]}]'::jsonb, '[{"de": "Das reparierte Auto steht vor der Tür.", "es": "El coche reparado está delante de la puerta.", "text": "Das reparierte Auto steht vor der Tür.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/c5d2c8a9-86de-579f-a3d6-5cdb5cde5f08.mp3"}, {"de": "Die spielenden Kinder lachen im Garten.", "es": "Los niños que juegan ríen en el jardín.", "text": "Die spielenden Kinder lachen im Garten.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ecd6c0ab-567a-573d-b623-85d256f8f89c.mp3"}, {"de": "Die Polizei fand die gestohlenen Fahrräder.", "es": "La policía encontró las bicicletas robadas.", "text": "Die Polizei fand die gestohlenen Fahrräder.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/b7f8541e-8f4d-581d-a3ab-6004e7a82968.mp3"}, {"de": "Wir warten auf den ankommenden Zug.", "es": "Esperamos el tren que está llegando.", "text": "Wir warten auf den ankommenden Zug.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/4ab9d47d-191b-530e-b0cd-652a571e6b69.mp3"}]'::jsonb, '[{"title": "«Ich bin spielend» no existe", "body": "El Partizip I NO es el gerundio español. «Estoy jugando» se dice «Ich spiele» o «Ich spiele gerade». El Partizip I solo vive delante de un sustantivo, o como adverbio: «Er kam lachend herein»."}, {"title": "Nunca dejes el participio sin terminación", "body": "Antepuesto, el participio es un adjetivo: «das repariert Auto» es agramatical. Debe declinarse: «das reparierte Auto», «ein repariertes Auto», «mit dem reparierten Auto». Y recuerda que el sustantivo alemán se escribe con mayúscula."}, {"title": "kochend ≠ gekocht: cambia quién actúa", "body": "«das kochende Wasser» es el agua que hierve ahora (activo); «das gekochte Ei» es el huevo ya cocido por alguien (pasivo). Elegir mal invierte el sentido: «die überzeugende Rede» convence, «die überzeugte Person» está convencida."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cuál es el Partizip I del verbo «lachen»?", "options": ["lachend", "gelacht", "lachte"], "answer": "lachend", "id": "u21q1"}, {"type": "multiple_choice", "prompt": "¿Qué significa «die weinenden Kinder»?", "options": ["los niños que lloran", "los niños a los que hicieron llorar", "los niños ya consolados"], "answer": "los niños que lloran", "id": "u21q2"}, {"type": "multiple_choice", "prompt": "Elige la frase correcta (invitado = ya invitado por alguien).", "options": ["Ich kenne den eingeladenen Gast.", "Ich kenne den eingeladene Gast.", "Ich kenne den eingeladenem Gast."], "answer": "Ich kenne den eingeladenen Gast.", "id": "u21q3"}, {"type": "cloze", "prompt": "Completa en alemán: «el bebé que duerme» (duerme ahora mismo).", "text": "Weck bitte das ___ Baby nicht!", "answer": "schlafende", "accepted": ["schlafenden", "schlafende"], "id": "u21q4"}, {"type": "cloze", "prompt": "Completa en alemán: «el ordenador reparado ayer» (= que fue reparado).", "text": "Der gestern ___ Computer funktioniert wieder.", "answer": "reparierte", "accepted": ["reparierten", "reparierte"], "id": "u21q5"}]'::jsonb)
