insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000005', 22, 'B2', 'Conectores avanzados (je…desto, weder…noch)', 'Cómo encadenar ideas como un nativo: «je … desto …» con su orden endiablado, «sowohl … als auch», «weder … noch» y «entweder … oder».', '[{"heading": "Je …, desto …: lo difícil es el orden", "body": "«Je + comparativo» abre una subordinada: el verbo se va AL FINAL. La segunda parte empieza por «desto + comparativo», y justo después va el verbo y luego el sujeto (inversión). «Umso» es sinónimo pleno de «desto».", "bullets": ["Je mehr ich lerne, …: el verbo «lerne» cierra.", "…, desto besser verstehe ich: comparativo, verbo, sujeto.", "«umso» = «desto»; ambas formas son correctas."]}, {"heading": "sowohl … als auch / weder … noch", "body": "«Sowohl A als auch B» une dos elementos: el verbo va en PLURAL. «Weder A noch B» significa «ni… ni…» y YA lleva la negación dentro: añadir «nicht» o «kein» es un error clásico del hispanohablante.", "bullets": ["Sowohl Anna als auch Tom kommen: verbo en plural.", "«Weder … noch …» nunca se combina con «nicht».", "Aquí «noch» no significa «todavía»."]}, {"heading": "entweder … oder (o… o…)", "body": "«Entweder A oder B» ofrece dos alternativas y no altera el orden habitual: si «entweder» abre la frase, el verbo conserva la segunda posición. No es negativo: solo plantea una elección.", "bullets": ["Entweder rufst du an oder du schreibst.", "Con «entweder» al inicio, verbo en segunda posición."]}]'::jsonb, '[{"de": "Je mehr ich lerne, desto besser verstehe ich.", "es": "Cuanto más estudio, mejor entiendo.", "text": "Je mehr ich lerne, desto besser verstehe ich.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/2a2556b4-05ed-5cba-aa9d-3e054e25beea.mp3"}, {"de": "Je länger ich in Berlin wohne, umso wohler fühle ich mich.", "es": "Cuanto más tiempo vivo en Berlín, más a gusto me siento.", "text": "Je länger ich in Berlin wohne, umso wohler fühle ich mich.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ee829ef8-5894-51de-8478-1106fc9d9918.mp3"}, {"de": "Ich mag weder Kaffee noch Tee.", "es": "No me gusta ni el café ni el té.", "text": "Ich mag weder Kaffee noch Tee.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ee638aa0-5c37-51cd-a183-8e130b9811d0.mp3"}, {"de": "Sowohl mein Bruder als auch meine Schwester wohnen in Hamburg.", "es": "Tanto mi hermano como mi hermana viven en Hamburgo.", "text": "Sowohl mein Bruder als auch meine Schwester wohnen in Hamburg.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/558c05a3-1e90-5aac-8305-26f7200c174a.mp3"}]'::jsonb, '[{"title": "Tras «je» el verbo NO va en segunda posición", "body": "«Je» introduce una subordinada, así que el verbo se marcha al final: «Je mehr ich übe…», no «Je mehr übe ich…». En la segunda mitad ocurre lo contrario: tras «desto/umso + comparativo» viene el verbo y después el sujeto."}, {"title": "«weder … noch» ya niega: fuera «nicht» y «kein»", "body": "Se dice «Ich habe weder Zeit noch Geld», nunca «Ich habe nicht weder Zeit noch Geld». Tampoco se sustituye «noch» por «oder»: la pareja fija es weder … noch."}, {"title": "«sowohl … als auch» exige verbo en plural", "body": "Son dos sujetos, aunque cada uno sea singular: «Sowohl er als auch sie kommen» (no «kommt»). Detalle de escritura: recuerda que los sustantivos alemanes van siempre con mayúscula inicial, aunque el corrector no lo distinga."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Qué frase tiene el orden correcto de «je … desto …»?", "options": ["Je mehr ich übe, desto sicherer werde ich.", "Je mehr übe ich, desto sicherer werde ich.", "Je mehr ich übe, desto ich werde sicherer."], "answer": "Je mehr ich übe, desto sicherer werde ich.", "id": "u22q1"}, {"type": "multiple_choice", "prompt": "Elige la frase correcta para decir «no bebo ni café ni té».", "options": ["Ich trinke weder Kaffee noch Tee.", "Ich trinke nicht weder Kaffee noch Tee.", "Ich trinke weder Kaffee oder Tee."], "answer": "Ich trinke weder Kaffee noch Tee.", "id": "u22q2"}, {"type": "cloze", "prompt": "Completa la pareja fija que significa «ni… ni…».", "text": "Er spricht ___ Französisch noch Italienisch.", "answer": "weder", "accepted": ["weder"], "id": "u22q3"}, {"type": "cloze", "prompt": "Completa la segunda mitad de la construcción abierta con «je».", "text": "Je früher wir anfangen, ___ schneller sind wir fertig.", "answer": "desto", "accepted": ["desto", "umso"], "id": "u22q4"}, {"type": "cloze", "prompt": "Completa el conector que significa «tanto… como…».", "text": "___ mein Vater als auch meine Mutter arbeiten hier.", "answer": "sowohl", "accepted": ["sowohl"], "id": "u22q5"}]'::jsonb)
