insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000005', 23, 'B2', 'Nominalización y perífrasis (Funktionsverbgefüge)', 'El alemán formal prefiere sustantivos a verbos: cualquier infinitivo se vuelve sustantivo neutro y hay bloques fijos (verbo + sustantivo) que se memorizan enteros.', '[{"heading": "El infinitivo se vuelve sustantivo neutro", "body": "Cualquier infinitivo puede usarse como sustantivo. Entonces es siempre NEUTRO (das) y se escribe con mayúscula: lesen → das Lesen, rauchen → das Rauchen. Equivale al español «el leer / la lectura». Suele llevar preposición: beim Lesen, zum Rauchen.", "bullets": ["Infinitivo nominalizado: siempre das, siempre mayúscula.", "Das Rauchen ist hier verboten.", "Beim Lesen entspannt er sich.", "Solo cambia en genitivo (des Lesens) y no tiene plural."]}, {"heading": "Nominalizar con sufijo: -ung, -heit, -keit", "body": "Muchos verbos dan un sustantivo en -ung, siempre femenino: prüfen → die Prüfung, entscheiden → die Entscheidung. Los adjetivos dan -heit o -keit, también femeninos: krank → die Krankheit, möglich → die Möglichkeit. El género es predecible; el sufijo, no.", "bullets": ["Verbo + -ung = femenino: die Prüfung, die Lösung.", "Adjetivo + -heit/-keit = femenino: die Krankheit, die Möglichkeit; también -sam y -haft.", "-keit tras -ig, -lich, -bar; -heit tras el resto; también -sam y -haft.", "Estilo nominal = registro escrito y administrativo."]}, {"heading": "Funktionsverbgefüge: el bloque verbo + sustantivo", "body": "El verbo pierde su significado y el sustantivo lo lleva todo. El verbo no se elige por lógica: se memoriza con el sustantivo, como una colocación. En español decimos «tomar una decisión»; en alemán es eine Entscheidung TREFFEN, nunca machen.", "bullets": ["eine Entscheidung treffen = tomar una decisión.", "etwas in Frage stellen = poner algo en duda.", "zur Verfügung stehen = estar a disposición.", "Abschied nehmen = despedirse."]}]'::jsonb, '[{"de": "Wir müssen heute eine Entscheidung treffen.", "es": "Tenemos que tomar una decisión hoy.", "text": "Wir müssen heute eine Entscheidung treffen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/55ac16dd-110d-5389-abc4-ce7d9354e2d6.mp3"}, {"de": "Niemand stellt seine Kompetenz in Frage.", "es": "Nadie pone en duda su competencia.", "text": "Niemand stellt seine Kompetenz in Frage.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/729053b3-63a8-5fee-b6fb-cab5637330b3.mp3"}, {"de": "Das Rauchen ist in allen Räumen verboten.", "es": "Fumar está prohibido en todas las salas.", "text": "Das Rauchen ist in allen Räumen verboten.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/6aa5b2b1-82d6-5f25-8ba9-cb7b917947f6.mp3"}, {"de": "Nach der Prüfung nahmen wir Abschied von ihr.", "es": "Después del examen nos despedimos de ella.", "text": "Nach der Prüfung nahmen wir Abschied von ihr.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/9bcca291-4202-5026-a7ab-3568e41f1fde.mp3"}]'::jsonb, '[{"title": "«Tomar una decisión» no es machen", "body": "El calco del español lleva a «eine Entscheidung machen» ✗. El verbo correcto es treffen: eine Entscheidung treffen. En estos bloques el verbo no se deduce del significado; se aprende pegado al sustantivo, igual que aprendes el artículo."}, {"title": "El infinitivo nominalizado va con mayúscula y con das", "body": "«lesen ist wichtig» ✗. Al nominalizar, la palabra pasa a sustantivo: Das Lesen ist wichtig. Es neutro sin excepción, aunque el verbo venga de una raíz que como sustantivo normal sería otro género (die Arbeit, pero das Arbeiten)."}, {"title": "-ung y -heit/-keit son femeninos, no neutros", "body": "Estudiantes dicen «das Prüfung» ✗ por influencia del neutro de los infinitivos. Toda nominalización en -ung, -heit o -keit es femenina: die Prüfung, die Krankheit, die Möglichkeit. Solo el infinitivo nominalizado es neutro."}]'::jsonb, '[{"type": "cloze", "prompt": "Completa con el verbo correcto del bloque fijo (tomar una decisión).", "text": "Wir müssen bald eine Entscheidung ___ .", "answer": "treffen", "accepted": ["treffen"], "id": "u23q1"}, {"type": "multiple_choice", "prompt": "¿Qué artículo lleva el infinitivo nominalizado de «rauchen»?", "options": ["das Rauchen", "der Rauchen", "die Rauchen"], "answer": "das Rauchen", "id": "u23q2"}, {"type": "cloze", "prompt": "Completa el bloque fijo: «poner en duda» (in Frage + verbo).", "text": "Er will meine Ergebnisse nicht in Frage ___ .", "answer": "stellen", "accepted": ["stellen"], "id": "u23q3"}, {"type": "multiple_choice", "prompt": "Nominaliza el verbo «prüfen». ¿Cuál es la forma correcta?", "options": ["die Prüfung", "das Prüfung", "der Prüfung"], "answer": "die Prüfung", "id": "u23q4"}, {"type": "cloze", "prompt": "Completa el bloque fijo: «despedirse de alguien» (Abschied + verbo).", "text": "Am Bahnhof mussten wir Abschied ___ .", "answer": "nehmen", "accepted": ["nehmen"], "id": "u23q5"}]'::jsonb)
