insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000005', 24, 'B2', 'Preposiciones de genitivo y adverbios preposicionales', 'Cierras el B2 con dos herramientas del alemán culto: las preposiciones que piden genitivo (wegen, trotz, während) y los adverbios da(r)- / wo(r)- para hablar de cosas.', '[{"heading": "Preposiciones con genitivo: wegen, trotz, während", "body": "Estas preposiciones piden genitivo: masculino y neutro toman des + -(e)s, femenino y plural toman der. Así se dice y se escribe en registro cuidado.", "bullets": ["wegen des Wetters, trotz des Regens, während der Woche", "Masculino/neutro: des Mannes, des Kindes", "Femenino/plural: der Arbeit, der Ferien", "Igual funcionan aufgrund, innerhalb, außerhalb"]}, {"heading": "Adverbios da(r)-: hablar de COSAS", "body": "Para personas usas preposición + pronombre. Para cosas eso no funciona: fusionas la preposición con da-. Si la preposición empieza por vocal, se mete una -r- de enlace.", "bullets": ["Personas: mit ihm, für sie, von ihnen", "Cosas: damit, dafür, davon, dazu", "Con vocal: darauf, darüber, darin, daran", "Ich warte darauf. (auf den Bus)"]}, {"heading": "Adverbios wo(r)-: preguntar por cosas", "body": "En la pregunta pasa lo mismo. Por personas preguntas con preposición más wen o wem; por cosas fusionas la preposición con wo-, y añades -r- ante vocal.", "bullets": ["Personas: Auf wen wartest du?", "Cosas: Worauf wartest du?", "Womit, wofür, wovon, worüber, woran", "También en subordinada: Ich weiß, worauf du wartest."]}]'::jsonb, '[{"de": "Wegen des schlechten Wetters bleiben wir zu Hause.", "es": "A causa del mal tiempo nos quedamos en casa.", "text": "Wegen des schlechten Wetters bleiben wir zu Hause.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e004bd2a-c8f4-5aff-8d0b-4f8da8956d29.mp3"}, {"de": "Trotz des Regens sind wir spazieren gegangen.", "es": "A pesar de la lluvia salimos a pasear.", "text": "Trotz des Regens sind wir spazieren gegangen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/824e27dc-ded8-5568-96e3-ccd508b06288.mp3"}, {"de": "Ich interessiere mich sehr dafür.", "es": "Me interesa mucho (eso).", "text": "Ich interessiere mich sehr dafür.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/97ea7770-145a-5e1d-9b27-647e9648ccbd.mp3"}, {"de": "Worüber habt ihr gestern gesprochen?", "es": "¿De qué hablasteis ayer?", "text": "Worüber habt ihr gestern gesprochen?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/14742334-1a73-580a-9867-d80a19867207.mp3"}]'::jsonb, '[{"title": "«für das» hablando de una cosa", "body": "El español dice «me intereso por eso» y traduces «ich interessiere mich für das» ✗. Si el referente es una cosa, el alemán fusiona: dafür. Igual damit, davon, dazu, darauf. La preposición suelta con pronombre queda para personas: für ihn, mit ihr."}, {"title": "La -r- de enlace se olvida", "body": "Ante preposición que empieza por vocal hay que meter una -r-: darauf, darüber, darin, daran, worauf, worüber, woran. Formas como «daauf» o «woüber» no existen. Regla corta: vocal detrás, -r- delante."}, {"title": "«wegen dem Wetter»: lo que se oye y lo que se escribe", "body": "En la lengua hablada oirás a diario wegen dem Wetter, trotz dem Regen, con dativo. No es un invento tuyo: está muy extendido y nadie te corregirá en un bar. Pero la norma escrita y el examen piden genitivo: wegen des Wetters. Escribe genitivo."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta: «Ich warte ___.» (espero el autobús, una cosa)", "options": ["darauf", "daauf", "auf ihn"], "answer": "darauf", "id": "u24q1"}, {"type": "multiple_choice", "prompt": "¿Cuál es la pregunta correcta por una COSA? «___ sprecht ihr?»", "options": ["Worüber", "Woüber", "Über wen"], "answer": "Worüber", "id": "u24q2"}, {"type": "cloze", "prompt": "Completa con la preposición de genitivo que significa «a causa de».", "text": "___ des schlechten Wetters bleiben wir zu Hause.", "answer": "Wegen", "accepted": ["wegen", "aufgrund", "auf Grund"], "id": "u24q3"}, {"type": "cloze", "prompt": "«während» rige genitivo: completa el artículo de «die Woche».", "text": "Während ___ Woche arbeite ich viel.", "answer": "der", "accepted": ["der"], "id": "u24q4"}, {"type": "cloze", "prompt": "El referente es una cosa (el proyecto), no una persona: usa el adverbio preposicional con «für».", "text": "Ich interessiere mich sehr ___.", "answer": "dafür", "accepted": ["dafuer", "dafur", "dafür"], "id": "u24q5"}]'::jsonb)
